return items.map((item) => {
  const source = item.json;
  const execution = source.execution ?? {};
  const workflow = source.workflow ?? {};
  const trigger = source.trigger ?? {};
  const triggerError = trigger.error ?? {};
  const error = execution.error ?? triggerError.cause ?? triggerError ?? {};

  return {
    json: {
      incidentType: 'n8n_workflow_failure',
      workflowId: workflow.id ?? 'unknown',
      workflowName: workflow.name ?? 'unknown',
      executionId: execution.id ?? null,
      executionUrl: execution.url ?? null,
      retryOf: execution.retryOf ?? null,
      lastNodeExecuted: execution.lastNodeExecuted ?? null,
      mode: execution.mode ?? trigger.mode ?? 'unknown',
      errorName: error.name ?? triggerError.name ?? 'WorkflowError',
      errorMessage: error.message ?? triggerError.message ?? 'No error message provided',
      timestamp: new Date().toISOString(),
      safeForClientHandoff: true
    }
  };
});

return items.map((item) => ({
  json: {
    ...item.json,
    routingHint: item.json.executionUrl
      ? 'Open executionUrl and inspect the lastNodeExecuted.'
      : 'The failure may have happened in the trigger before an execution record was created.',
    nextAction: 'Replace this node with Slack, email, ticket creation, or database logging.'
  }
}));
